import React from "react";
import "./DashboardPage.css";

const DashboardPage: React.FC = () => {
    return (
        <div className="dashboard-container">
            <h1 className="dashboard-title">Dashboard</h1>
            <p className="dashboard-subtitle">Welcome to the Dashboard!</p>

            <div className="dashboard-cards">
                <div className="card">
                    <h2>Total Users</h2>
                    <p className="count">120</p>
                </div>
                <div className="card">
                    <h2>Active Sessions</h2>
                    <p className="count">15</p>
                </div>
                <div className="card">
                    <h2>Pending Tasks</h2>
                    <p className="count">8</p>
                </div>
            </div>

            <p className="dashboard-info">
                Here you can monitor key metrics, navigate to different sections, and manage system settings.
            </p>
        </div>
    );
};

export default DashboardPage;
